1	import { Stagehand } from "../lib/v3";
2	import StagehandConfig from "@/stagehand.config";
3	import chalk from "chalk";
4	import { connectToMCPServer } from "../../lib/mcp/connection";
5	
6	async function main() {
7	  console.log(`\n${chalk.bold("Stagehand 🤘 MCP Demo")}\n`);
8	  console.log(process.env.NOTION_TOKEN);
9	
10	  // Initialize Stagehand
11	  const stagehand = new Stagehand({
12	    ...StagehandConfig,
13	    env: "LOCAL",
14	    experimental: true,
15	  });
16	  await stagehand.init();
17	
18	  const notionClient = await connectToMCPServer({
19	    command: "npx",
20	    args: ["-y", "@notionhq/notion-mcp-server"],
21	    env: {
22	      NOTION_TOKEN: process.env.NOTION_TOKEN,
23	    },
24	  });
25	
26	  try {
27	    const page = stagehand.context.pages()[0];
28	
29	    // Create a computer use agent
30	    const agent = stagehand.agent({
31	      mode: "hybrid",
32	      // For Anthropic, use claude-sonnet-4-6 or claude-sonnet-4-5-20250929
33	      model: "anthropic/claude-sonnet-4-6",
34	      systemPrompt: `You are a helpful assistant that can use a web browser.
35	      You are currently on the following page: ${page.url()}.
36	      Do not ask follow up questions, the user will trust your judgement.
37	      You have access to the Notion MCP.`,
38	      integrations: [notionClient],
39	    });
40	
41	    // Navigate to the Browserbase careers page
42	    await page.goto("https://www.google.com");
43	
44	    // Define the instruction for the CUA
45	    const instruction =
46	      "Check the Agent Tasks page in notion, read your tasks, perform them and update the notion page with the results.";
47	    console.log(`Instruction: ${chalk.white(instruction)}`);
48	
49	    // Execute the instruction
50	    const result = await agent.execute({
51	      instruction,
52	      maxSteps: 50,
53	    });
54	
55	    console.log(`${chalk.green("✓")} Execution complete`);
56	    console.log(`${chalk.yellow("⤷")} Result:`);
