        ${DEFAULT_EVAL_CATEGORIES.slice(10)
          .map((c) => chalk.yellow(c))
          .join(", ")}
  `;

  if (!detailed)
    return `${header}\n\n${synopsis}\n\nFor more details: ${chalk.bold(
      "pnpm run evals -man\n",
    )}`;

  const externalBenchmarksSection = dedent`
